That's great.  Your suggestion works well there.

If I make the example more realistic, meaning that we're sending these functions in to an existing C++ template library, I arrive at my current challenge.  Our "subobjects" get copied and passed into our functions. (What is happening individuals getting copied in the simulation to be used as "parents", and the existing individuals get over-written as offspring.)  

Here's what I'm talking about (simplified to avoid the copying in this specific case):

```cpp
#include <pybind11/pybind11.h>
#include <pybind11/stl.h>
#include <pybind11/functional.h>
#include <pybind11/stl_bind.h>
#include <iostream>

namespace py = pybind11;

struct subobject
{
    int x;
    subobject(int x_) : x(x_) {}
    subobject(const subobject& s) : x(s.x)
    {
        std::cout << "subobject copied\n";
    }
};

struct object
{
    subobject s;
    object(int x) : s(x) {}
    object(const object& o) : s(o.s) { std::cout << "object copied\n"; }
};

using sf = std::function<void(const subobject&)>;
using of = std::function<void(const object&)>;

struct process_subobject
{
    inline void
    operator()(const subobject& o) const
    {
        std::cout << "cpp callable doing the job!\n";
        std::cout << o.x << '\n';
    }
};

template <typename sf_>
void
external_lib_template_fxn(object& o, const sf_ sf)
{
    /* The "real" project
     * would work on a copy
     * of o.s, but this
     * is sufficient to
     * show that there's still a copy
     */
    std::cout << "about to call our policy\nin external library...\n";
    sf(o.s);
    std::cout << "done with policy call\n";
}

void
doit(object& o, py::function sf_, of of_)
{
    std::cout << "pass off to another lib\nthat works on the subobject\n";
    external_lib_template_fxn(o, sf_);
    std::cout << "work on object in our Python package:\n";
    of_(o);
}

PYBIND11_PLUGIN(copying4)
{
    py::module m("copying4", "expensive copying");

    py::class_<subobject>(m, "Subobject")
        .def(py::init<int>())
        .def_readonly("x", &subobject::x);

    py::class_<object>(m, "Object")
        .def(py::init<int>())
        .def_readonly("s", &object::s);

    // This appears automagically castable
    // to py::function
    py::class_<process_subobject>(m, "ProcessSubobject")
        .def(py::init<>())
        .def("__call__", [](const process_subobject& po,
                            const subobject& s) -> void { return po(s); });

    m.def("doit", &doit);

    return m.ptr();
}
```

And the script:

```py
import copying4

o=copying4.Object(4)

def work_on_subobj(s):
    print(s.x)

def work_on_obj(o):
    print(o.s.x)

po = copying4.ProcessSubobject()

copying4.doit(o,po,work_on_obj)
```

I will note that I can get rid of the subobject copy in the "library" code by modifying the python script as follows:

```py
s=o.s
copying4.doit(o,po,work_on_obj)
```

So, that's great, but that does not model the behavior of the actual library (which copies input data).

My current thought is to force users to write these custom functions using C++11/pybind11, and have those objects follow an API requiring that they can return a properly-bound object to the C++ code, such that pybind11 never has to see any of it.  This may not be so bad for right now, as all other extensions could be written in pure Python and not suffer from these copying issues (insofar as I've tested things...).  Most other extensions would model "work_on_object".

