But this clears exactly these two frames. What if I have a deeper traceback?
Can't you set just another `co_flag` on obfuscation for each code object (eg. `CO_PYARMOR_FLAG`).

Now initially set the getter:
```c
static PyObject *
frame_getlocals(PyObject *frame, void *closure)
{
  PyObject *f_code = *(PyObject**)((char*)frame + f_code_offset);
  PyObject *co_code = *(PyObject**)((char*)f_code + co_code_offset);
  int co_flags = *(int*)((char*)f_code + co_flags_offset);

  if (co_flags & CO_PYARMOR_FLAG) {
    PyObject *d = Py_BuildValue("{}");
    Py_IncRef(d);
    return d;
  }
  return original_frame_getloals(frame, closure);
}
static void* original_frame_getloals = *(void**)((char*)frame_getsetlist + sizeof(char*));
*(void**)((char*)frame_getsetlist + sizeof(char*)) = (void*)frame_getlocals;
```
And clearing the tracebacks in `__wraparmor__`:
```c
static inquiry tp_clear = NULL;
static void* original_frame_getloals = NULL;

static PyObject*
__wraparmor__(PyObject *self, PyObject *args)
{
    ...
    // If tb is None, no frame will be clear
    if (tb != None) {
        // Get frame of `wrapper`
        PyFrameObject *frame = PyEval_GetFrame();

        if (!tp_clear) {
            tp_clear = (frame->ob_type)->tp_clear;
        }
        // Only clear frames of initially obuscated functions
          while (tb) {
            PyObject *tb_frame = tb -> tb_frame;
            PyObject *f_code = *(PyObject**)((char*)tb_frame + f_code_offset);
            PyObject *co_code = *(PyObject**)((char*)f_code + co_code_offset);
            int co_flags = *(int*)((char*)f_code + co_flags_offset);

            if (co_flags & CO_PYARMOR_FLAG)
              tp_clear(tb_frame);
            tb = tb->tb_next;
          }
    }
}
```
The advantage is, that even callbacks from encrypted code to outside code are secured of getting its `f_locals`.

